-- ============================================================
-- 仙道 · xt_map_node 种子数据
-- id 显式赋值（仅种子数据场景）确保 neighbors 直接引用已确定 ID
-- neighbors: [{"targetId": N, "cost": N}, ...]
-- specialties: [{"templateId": N, "weight": N}, ...]
-- travel_events: [{"eventType": "xxx", "weight": N}, ...]
-- monster_encounters: [{"templateId": N, "weight": N, "min": N, "max": N}, ...]
-- ============================================================


SELECT setval('xt_map_node_id_seq', (SELECT COALESCE(MAX(id), 0) FROM xt_map_node));
