INSERT INTO xt_map_node (id, name, description, map_type, level_requirement, neighbors, specialties, travel_events, monster_encounters) VALUES
(1,'青山镇','青山脚下小镇灵气稀薄胜在安稳。镇口石碑"天道酬勤"被渡劫失败的散修一剑劈成两半至今未修。','SAFE_TOWN',1,jsonb_build_array(jsonb_build_object('targetId',8,'cost',5)),'[]'::jsonb,'[]'::jsonb,'[]'::jsonb),
(2,'落霞坊市','散修云集的坊市地摊摆满自称上古大能遗物的破烂。最热闹的地方永远是灵石兑换处。','SAFE_TOWN',1,jsonb_build_array(jsonb_build_object('targetId',4,'cost',6),jsonb_build_object('targetId',8,'cost',6),jsonb_build_object('targetId',9,'cost',8)),'[]'::jsonb,'[]'::jsonb,'[]'::jsonb),
(3,'天阙城','修仙界第一雄城城墙以星辰铁铸就刻有上古诛仙阵。城门口常年排队——被城卫拦下查验道心的散修太多。','SAFE_TOWN',30,jsonb_build_array(jsonb_build_object('targetId',5,'cost',10),jsonb_build_object('targetId',6,'cost',10),jsonb_build_object('targetId',7,'cost',15),jsonb_build_object('targetId',11,'cost',10),jsonb_build_object('targetId',12,'cost',12),jsonb_build_object('targetId',20,'cost',6)),'[]'::jsonb,'[]'::jsonb,'[]'::jsonb),
(4,'铸剑山','终年炉火不熄的山城空气中弥漫铁锈煤烟。第一铁律：定制法器预算必超三倍——煤灰迷眼看谁都像有钱人。','SAFE_TOWN',15,jsonb_build_array(jsonb_build_object('targetId',2,'cost',6),jsonb_build_object('targetId',9,'cost',10),jsonb_build_object('targetId',15,'cost',15)),'[]'::jsonb,'[]'::jsonb,'[]'::jsonb),
(5,'灵药谷','群山环抱幽谷四季如春灵药遍地。谷口木牌："入谷须知：一不要踩老夫聚灵草二不要偷老夫灵芝三违反前两条请与噬心魔藤解释。"被划掉的第四条："四不要相信前三条——那藤是假的但火球术是真的。"','SAFE_TOWN',25,jsonb_build_array(jsonb_build_object('targetId',3,'cost',10),jsonb_build_object('targetId',11,'cost',10),jsonb_build_object('targetId',13,'cost',15),jsonb_build_object('targetId',14,'cost',12)),'[]'::jsonb,'[]'::jsonb,'[]'::jsonb),
(6,'须弥山','佛门圣地高耸入云。山腰千年古刹——扫地僧随手一挥便能山河倒流。寺门口横幅："放下屠刀立地成佛；放下法器灵石归我。"','SAFE_TOWN',60,jsonb_build_array(jsonb_build_object('targetId',3,'cost',10),jsonb_build_object('targetId',11,'cost',15),jsonb_build_object('targetId',20,'cost',12),jsonb_build_object('targetId',27,'cost',18)),'[]'::jsonb,'[]'::jsonb,'[]'::jsonb),
(7,'天机阁','悬于云端的神秘阁楼修真界情报中心。口头禅："给够灵石连隔壁护山大阵阵眼都能画给你。"大部分修士付了灵石才反应过来可能是假情报。','SAFE_TOWN',80,jsonb_build_array(jsonb_build_object('targetId',3,'cost',15),jsonb_build_object('targetId',24,'cost',10),jsonb_build_object('targetId',17,'cost',12)),'[]'::jsonb,'[]'::jsonb,'[]'::jsonb),
(8,'青云山外门','青云宗外门修炼之地。山腰老松树皮刻满"筑基失败道心破碎"、"今日又被师兄抢了灵石"之类涂鸦。','TRAINING_ZONE',1,jsonb_build_array(jsonb_build_object('targetId',1,'cost',5),jsonb_build_object('targetId',2,'cost',6),jsonb_build_object('targetId',11,'cost',10),jsonb_build_object('targetId',9,'cost',8)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='聚灵草'),'weight',40),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='玄铁'),'weight',30),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='星辰砂'),'weight',20),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='龙鳞'),'weight',10)),jsonb_build_array(jsonb_build_object('eventType','FIND_TREASURE','weight',15),jsonb_build_object('eventType','AMBUSH','weight',5)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='山精'),'weight',40,'min',1,'max',3),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='石灵'),'weight',30,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='妖狼'),'weight',20,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='食灵鼠'),'weight',10,'min',1,'max',3))),
(9,'枯骨林入口','远古战场边缘遍地白骨阴风阵阵。月圆之夜能听到亡魂低语。有经验的散修都知道在这捡破烂比历练来灵石快。','TRAINING_ZONE',10,jsonb_build_array(jsonb_build_object('targetId',2,'cost',8),jsonb_build_object('targetId',8,'cost',8),jsonb_build_object('targetId',10,'cost',8)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='凤凰翎'),'weight',40),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='九天息壤'),'weight',30),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='万年寒铁'),'weight',20),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='血菩提'),'weight',10)),jsonb_build_array(jsonb_build_object('eventType','AMBUSH','weight',30),jsonb_build_object('eventType','FIND_TREASURE','weight',20)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='石魔'),'weight',40,'min',1,'max',3),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='枯骨将军'),'weight',30,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='噬魂鬼'),'weight',20,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='食人花妖'),'weight',10,'min',1,'max',2))),
(10,'枯骨林深处','越往深处白骨越密。空气中弥漫腐朽气息偶能看到走火入魔的倒霉修士遗物还没人捡。','TRAINING_ZONE',20,jsonb_build_array(jsonb_build_object('targetId',9,'cost',8),jsonb_build_object('targetId',12,'cost',12),jsonb_build_object('targetId',13,'cost',15),jsonb_build_object('targetId',14,'cost',10)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='舍利子'),'weight',40),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='九转金莲种子'),'weight',30),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='千年灵芝孢子'),'weight',20),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='冰莲种子'),'weight',10)),jsonb_build_array(jsonb_build_object('eventType','AMBUSH','weight',40),jsonb_build_object('eventType','FIND_TREASURE','weight',15)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='九尾妖狐'),'weight',40,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='噬魂鬼'),'weight',30,'min',1,'max',3),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='食人花妖'),'weight',20,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='九头蛇'),'weight',10,'min',1,'max',1))),
(11,'青云山内门','青云宗真正修炼圣地——灵气浓郁几乎液化在此修炼一日胜过外门十日。前提不被内门弟子当练功靶子。','TRAINING_ZONE',25,jsonb_build_array(jsonb_build_object('targetId',8,'cost',10),jsonb_build_object('targetId',3,'cost',10),jsonb_build_object('targetId',20,'cost',15),jsonb_build_object('targetId',5,'cost',10),jsonb_build_object('targetId',6,'cost',15)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='血菩提'),'weight',40),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='星辰砂'),'weight',30),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='龙鳞'),'weight',20),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='舍利子'),'weight',10)),jsonb_build_array(jsonb_build_object('eventType','FIND_TREASURE','weight',25),jsonb_build_object('eventType','AMBUSH','weight',10)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='修罗战魂'),'weight',40,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='九尾妖狐'),'weight',30,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='九头蛇'),'weight',20,'min',1,'max',1),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='赤焰蛟龙'),'weight',10,'min',1,'max',1))),
(12,'修罗场外围','修罗道入口空气中充满狂暴杀意——修为不足轻则心神不宁重则当场疯魔。名言:"修罗场里没有道友只有对手。"','TRAINING_ZONE',35,jsonb_build_array(jsonb_build_object('targetId',3,'cost',12),jsonb_build_object('targetId',10,'cost',12),jsonb_build_object('targetId',13,'cost',15),jsonb_build_object('targetId',21,'cost',15),jsonb_build_object('targetId',14,'cost',15)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='九天息壤'),'weight',40),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='血菩提'),'weight',30),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='舍利子'),'weight',20),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='万年寒铁'),'weight',10)),jsonb_build_array(jsonb_build_object('eventType','AMBUSH','weight',50),jsonb_build_object('eventType','FIND_TREASURE','weight',10)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='玄冥龟'),'weight',40,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='赤焰蛟龙'),'weight',30,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='噬心魔'),'weight',20,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='飞天夜叉'),'weight',10,'min',1,'max',1))),
(13,'万妖谷','万妖汇聚之地上古大妖陨落后所化。最危险的不是妖兽——是看起来人畜无害的花花草草下一秒就把你吞了。','TRAINING_ZONE',40,jsonb_build_array(jsonb_build_object('targetId',10,'cost',15),jsonb_build_object('targetId',12,'cost',15),jsonb_build_object('targetId',22,'cost',12),jsonb_build_object('targetId',19,'cost',10)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='凤凰翎'),'weight',40),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='龙血草'),'weight',30),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='血菩提'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='龙鳞'),'weight',5)),jsonb_build_array(jsonb_build_object('eventType','AMBUSH','weight',45),jsonb_build_object('eventType','FIND_TREASURE','weight',15)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='噬心魔'),'weight',40,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='飞天夜叉'),'weight',30,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='远古石像鬼'),'weight',25,'min',1,'max',1),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='不死凤凰'),'weight',5,'min',1,'max',1))),
(14,'亡魂沼泽','终年瘴气笼罩。地底亡魂被瘴气束缚日复一日游荡。有修士修炼毒功时意外发现沼泽泥鳅炖汤特别好喝——从此多了一群吃货修士。','TRAINING_ZONE',18,jsonb_build_array(jsonb_build_object('targetId',10,'cost',10),jsonb_build_object('targetId',12,'cost',15),jsonb_build_object('targetId',5,'cost',12)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='幽冥铁'),'weight',35),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='魔血石'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='虚空结晶'),'weight',20),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='火灵芝'),'weight',15),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='星辰花瓣'),'weight',5)),jsonb_build_array(jsonb_build_object('eventType','AMBUSH','weight',35),jsonb_build_object('eventType','FIND_TREASURE','weight',25),jsonb_build_object('eventType','WEATHER','weight',15)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='沼泽泥怪'),'weight',35,'min',1,'max',3),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='火蝎'),'weight',30,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='沙暴蜥蜴'),'weight',20,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='星尘蝶'),'weight',15,'min',1,'max',2))),
(15,'烈焰荒漠','一望无际沙海地表温度高到能把灵石烤化。沙漠中能看到修士干尸紧攥水袋——"水比灵石贵"。火灵石矿脉让人趋之若鹜十进八迷路两烤成干。','TRAINING_ZONE',35,jsonb_build_array(jsonb_build_object('targetId',4,'cost',15),jsonb_build_object('targetId',13,'cost',15),jsonb_build_object('targetId',16,'cost',12),jsonb_build_object('targetId',20,'cost',10)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='火灵石'),'weight',30),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='星核碎片'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='虚空结晶'),'weight',20),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='混沌元晶'),'weight',15),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='灵茶叶'),'weight',10)),jsonb_build_array(jsonb_build_object('eventType','AMBUSH','weight',40),jsonb_build_object('eventType','FIND_TREASURE','weight',25),jsonb_build_object('eventType','WEATHER','weight',10)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='沙暴蜥蜴'),'weight',35,'min',1,'max',3),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='熔岩巨兽'),'weight',30,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='虚空行者'),'weight',20,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='暗影刺客'),'weight',15,'min',1,'max',2))),
