(17,'魔界裂隙','魔界人界交界之处。裂隙透出魔气让人心神不宁——修为低靠近会幻觉最常见修炼五百年没突破看到自己飞升——然后被魔物一巴掌拍醒。','TRAINING_ZONE',65,jsonb_build_array(jsonb_build_object('targetId',16,'cost',15),jsonb_build_object('targetId',7,'cost',12),jsonb_build_object('targetId',26,'cost',12),jsonb_build_object('targetId',27,'cost',18)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='虚空结晶'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='魔血石'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='神血石'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='灵茶叶'),'weight',15),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='天道花瓣'),'weight',10)),jsonb_build_array(jsonb_build_object('eventType','AMBUSH','weight',50),jsonb_build_object('eventType','FIND_TREASURE','weight',20)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='吞噬魔'),'weight',30,'min',1,'max',3),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='远古武神'),'weight',25,'min',1,'max',3),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='暗影刺客'),'weight',25,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='虚空领主'),'weight',20,'min',1,'max',2))),
(18,'无尽海','修真大陆边缘没有尽头海洋。对面据说还有另一片大陆——最大未解之谜:"对面到底有什么？"自从千年前大乘修士驾舟出海至今未归，再无人敢验证。','TRAINING_ZONE',80,jsonb_build_array(jsonb_build_object('targetId',17,'cost',15),jsonb_build_object('targetId',7,'cost',15),jsonb_build_object('targetId',27,'cost',20),jsonb_build_object('targetId',30,'cost',20),jsonb_build_object('targetId',19,'cost',15)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='虚空结晶'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='神血石'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='混沌元晶'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='天道花瓣'),'weight',25)),jsonb_build_array(jsonb_build_object('eventType','AMBUSH','weight',45),jsonb_build_object('eventType','FIND_TREASURE','weight',25),jsonb_build_object('eventType','WEATHER','weight',5)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='虚空领主'),'weight',30,'min',1,'max',3),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='远古武神'),'weight',25,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='寒冰女王'),'weight',25,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='混沌之眼'),'weight',20,'min',1,'max',2))),
