(20,'九天玄刹','悬浮于万米高空的遗迹之城陨落仙帝道场。踏上此地的修士都默念："三十年河东三十年河西莫欺少年穷。"然多数人十分钟内被雷劈成焦炭。','HIDDEN_ZONE',50,jsonb_build_array(jsonb_build_object('targetId',3,'cost',6),jsonb_build_object('targetId',11,'cost',15),jsonb_build_object('targetId',24,'cost',10),jsonb_build_object('targetId',6,'cost',12)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='天道碎片'),'weight',30),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='混沌元晶'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='神血石'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='虚空结晶'),'weight',20)),jsonb_build_array(jsonb_build_object('eventType','FIND_TREASURE','weight',35),jsonb_build_object('eventType','AMBUSH','weight',30)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='远古石像鬼'),'weight',35,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='不死凤凰'),'weight',30,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='修罗王'),'weight',20,'min',1,'max',1),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='万年妖藤'),'weight',15,'min',1,'max',1))),
(21,'修罗场核心','修罗道核心杀意凝成实质在空中形成红色血雾。传说有人在此得修罗传承——第二天就被另一个得传承者杀了。','HIDDEN_ZONE',60,jsonb_build_array(jsonb_build_object('targetId',12,'cost',15),jsonb_build_object('targetId',22,'cost',12),jsonb_build_object('targetId',24,'cost',8)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='神血石'),'weight',30),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='混沌元晶'),'weight',30),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='虚空结晶'),'weight',20),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='天道碎片'),'weight',20)),jsonb_build_array(jsonb_build_object('eventType','AMBUSH','weight',55),jsonb_build_object('eventType','FIND_TREASURE','weight',20)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='修罗王'),'weight',35,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='远古黑龙'),'weight',30,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='万年妖藤'),'weight',20,'min',1,'max',1),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='不死凤凰'),'weight',15,'min',1,'max',1))),
(22,'龙渊入口','通向龙族秘境入口。洞口吞吐龙息修为不足七窍流血。洞口古篆:"入此门者生死自负。若得龙族认可可得龙血灌体。"','HIDDEN_ZONE',70,jsonb_build_array(jsonb_build_object('targetId',13,'cost',12),jsonb_build_object('targetId',21,'cost',12),jsonb_build_object('targetId',23,'cost',15)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='混沌元晶'),'weight',30),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='天道碎片'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='龙血草'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='神血石'),'weight',20)),jsonb_build_array(jsonb_build_object('eventType','FIND_TREASURE','weight',40),jsonb_build_object('eventType','AMBUSH','weight',30)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='远古黑龙'),'weight',35,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='剑痴残魂'),'weight',30,'min',1,'max',1),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='天劫雷兽'),'weight',20,'min',1,'max',1),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='修罗王'),'weight',15,'min',1,'max',1))),
(23,'龙渊深处','真龙沉眠之地龙威压迫之下一切生灵皆需俯首。龙王每隔千年醒来一次——在它醒来时进入的散修十有九个成点心。','HIDDEN_ZONE',85,jsonb_build_array(jsonb_build_object('targetId',22,'cost',15),jsonb_build_object('targetId',24,'cost',10)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='天道碎片'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='神血石'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='九天息壤'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='凤凰翎'),'weight',25)),jsonb_build_array(jsonb_build_object('eventType','FIND_TREASURE','weight',50),jsonb_build_object('eventType','AMBUSH','weight',30)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='天劫雷兽'),'weight',30,'min',1,'max',1),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='混沌巨兽'),'weight',30,'min',1,'max',1),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='远古黑龙'),'weight',20,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='远古石像鬼'),'weight',20,'min',1,'max',2))),
(24,'仙界遗迹外围','仙界残存一角空气中残余仙气可直接洗髓伐脉。但常年盘踞各路老怪物——新来散修通常被热情招待比如先交出你身上值钱的玩意儿。','HIDDEN_ZONE',90,jsonb_build_array(jsonb_build_object('targetId',20,'cost',10),jsonb_build_object('targetId',21,'cost',8),jsonb_build_object('targetId',23,'cost',10),jsonb_build_object('targetId',25,'cost',12),jsonb_build_object('targetId',7,'cost',10)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='天道碎片'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='神血石'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='星辰砂'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='混沌元晶'),'weight',25)),jsonb_build_array(jsonb_build_object('eventType','FIND_TREASURE','weight',45),jsonb_build_object('eventType','AMBUSH','weight',35)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='剑痴残魂'),'weight',30,'min',1,'max',1),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='天劫雷兽'),'weight',30,'min',1,'max',1),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='混沌巨兽'),'weight',20,'min',1,'max',1),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='远古石像鬼'),'weight',20,'min',1,'max',2))),
(25,'仙界遗迹核心','据说此处曾是仙帝寝宫正殿匾额三字:"自在天"。大道五十天衍四九人遁其一——追寻那遁去的一正是所有修士终极目标——这里或许就是答案也或许什么都没有。毕竟来过的修士没有一个回来的。','HIDDEN_ZONE',100,jsonb_build_array(jsonb_build_object('targetId',24,'cost',12)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='天道碎片'),'weight',30),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='混沌元晶'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='九转金莲种子'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='九天息壤'),'weight',20)),jsonb_build_array(jsonb_build_object('eventType','FIND_TREASURE','weight',50),jsonb_build_object('eventType','AMBUSH','weight',40)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='混沌巨兽'),'weight',30,'min',1,'max',1),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='天劫雷兽'),'weight',30,'min',1,'max',1),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='远古石像鬼'),'weight',20,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='修罗王'),'weight',20,'min',1,'max',2))),
