(27,'远古神墓','上古不知名神祇安息之地。墓室入口血红古篆:"擅入者死"。下面刻了小字:"我家就是被擅入者灭门的——今天我就要进去看看。——散修王五四留"。几千年王五四至今未出但事迹激励一代又一代。','HIDDEN_ZONE',75,jsonb_build_array(jsonb_build_object('targetId',26,'cost',15),jsonb_build_object('targetId',6,'cost',18),jsonb_build_object('targetId',18,'cost',18),jsonb_build_object('targetId',28,'cost',12),jsonb_build_object('targetId',19,'cost',15)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='神血石'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='混沌元晶'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='天道碎片'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='天道花瓣'),'weight',25)),jsonb_build_array(jsonb_build_object('eventType','AMBUSH','weight',45),jsonb_build_object('eventType','FIND_TREASURE','weight',30)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='魔界之主'),'weight',30,'min',1,'max',3),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='天道化身'),'weight',30,'min',1,'max',3),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='混沌之眼'),'weight',25,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='万剑剑灵'),'weight',15,'min',1,'max',2))),
(28,'天道之路','通往飞升台的道路。路两旁无数修士墓碑——每座代表一个飞升失败的灵魂。路口石碑:"飞升之路九死一生前路不悔仙道无悔。"某散修刻批注:"一万三千四百二十六号报到——啊我看到光了那一定是飞升之光吧！"碑后刻:"不是——那是你身后金丹期的火球术。"','HIDDEN_ZONE',95,jsonb_build_array(jsonb_build_object('targetId',27,'cost',12),jsonb_build_object('targetId',25,'cost',15),jsonb_build_object('targetId',30,'cost',10)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='混沌元晶'),'weight',30),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='天道碎片'),'weight',30),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='天道花瓣'),'weight',40)),jsonb_build_array(jsonb_build_object('eventType','AMBUSH','weight',50),jsonb_build_object('eventType','FIND_TREASURE','weight',30)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='混沌之眼'),'weight',30,'min',1,'max',3),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='万剑剑灵'),'weight',30,'min',1,'max',3),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='上古龙神'),'weight',20,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='飞升失败者'),'weight',20,'min',1,'max',2))),
(29,'虚空裂缝','现世与虚空之间不稳定空间。裂缝喷涌混沌之气——疯子修士最爱来因为修炼一天抵十年——至于修完是人是妖是死是活不在统计范围。','HIDDEN_ZONE',80,jsonb_build_array(jsonb_build_object('targetId',17,'cost',10),jsonb_build_object('targetId',7,'cost',12),jsonb_build_object('targetId',27,'cost',12)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='混沌元晶'),'weight',35),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='天道碎片'),'weight',35),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='天道花瓣'),'weight',30)),jsonb_build_array(jsonb_build_object('eventType','AMBUSH','weight',60),jsonb_build_object('eventType','FIND_TREASURE','weight',10)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='虚空领主'),'weight',30,'min',1,'max',3),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='魔界之主'),'weight',30,'min',1,'max',3),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='万剑剑灵'),'weight',20,'min',1,'max',2),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='飞升失败者'),'weight',20,'min',1,'max',2))),
(30,'混沌之源','万物本源之地。没人知道在哪——连去过的人都说不清楚因为进去再出来的人记忆支离破碎。不是标注地点而是一种状态——修炼到一定境界它会来找你——也可能只是错觉。修真界最大未解之谜:"混沌之源存不存在？"道观说存在魔教说不存在——打了一万年。','HIDDEN_ZONE',100,jsonb_build_array(jsonb_build_object('targetId',28,'cost',10),jsonb_build_object('targetId',25,'cost',12),jsonb_build_object('targetId',29,'cost',12)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='混沌元晶'),'weight',25),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='天道碎片'),'weight',35),jsonb_build_object('templateId',(SELECT id FROM xt_item_template WHERE name='天道花瓣'),'weight',40)),jsonb_build_array(jsonb_build_object('eventType','AMBUSH','weight',50),jsonb_build_object('eventType','FIND_TREASURE','weight',30)),jsonb_build_array(jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='万剑剑灵'),'weight',25,'min',1,'max',3),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='上古龙神'),'weight',30,'min',1,'max',3),jsonb_build_object('templateId',(SELECT id FROM xt_monster_template WHERE name='飞升失败者'),'weight',45,'min',1,'max',3)));
